#define MAX_COMMIT_MSG 256
#define MAX_HASH 64
#define MAX_LINE 1024

typedef struct {
    char name[MAX_FILENAME];
    char hash[MAX_HASH];
} FileEntry;

typedef struct {
    char commit_hash[MAX_HASH];
