// Write commit to disk
void write_commit(Commit* commit) {
    char object_path[MAX_FILENAME];
    snprintf(object_path, sizeof(object_path), ".min/objects/%s", commit->commit_hash);

    FILE* file = fopen(object_path, "w");
    fprintf(file, "parent: %s\n", commit->parent_hash);
    fprintf(file, "message: %s\n", commit->message);
    fprintf(file, "timestamp: %ld\n", commit->timestamp);
    fprintf(file, "files:\n");

    for (int i = 0; i < commit->file_count; i++) {
        fprintf(file, "%s %s\n", commit->files[i].name, commit->files[i].hash);
    }

    fclose(file);
}

// Read commit from disk
int read_commit(const char* hash, Commit* commit) {
    char object_path[MAX_FILENAME];
    snprintf(object_path, sizeof(object_path), ".minigit/objects/%s", hash);

    FILE* file = fopen(object_path, "r");
    if (!file) return 0;

    strcpy(commit->commit_hash, hash);

    char line[MAX_LINE];
    fgets(line, sizeof(line), file);
    sscanf(line, "parent: %s\n", commit->parent_hash);

    fgets(line, sizeof(line), file);
    sscanf(line, "message: %[^\n]\n", commit->message);

    fgets(line, sizeof(line), file);
    sscanf(line, "timestamp: %ld\n", &commit->timestamp);

    fgets(line, sizeof(line), file); // "files:"

    commit->file_count = 0;
    while (fgets(line, sizeof(line), file)) {
        sscanf(line, "%s %s\n", commit->files[commit->file_count].name,
               commit->files[commit->file_count].hash);
        commit->file_count++;
    }

    fclose(file);
    return 1;
}

