// Checkout command
void checkout(const char* commit_hash) {
    // If commit_hash is "HEAD", get current head
    char target_hash[MAX_HASH];
    if (strcmp(commit_hash, "HEAD") == 0) {
        get_head(target_hash);
    } else {
        strcpy(target_hash, commit_hash);
    }

    // Read commit
    Commit commit;
    if (!read_commit(target_hash, &commit)) {
        printf("Invalid commit hash\n");
        return;
    }

    // Update working directory
    for (int i = 0; i < commit.file_count; i++) {
        char* file_hash = commit.files[i].hash;
        const char* filename = commit.files[i].name;

        // Read file content from objects
        long size;
        char* content = read_object(file_hash, &size);
        if (content) {
            // Create directory structure if needed
            char* last_slash = strrchr(filename, '/');
            if (last_slash) {
                *last_slash = '\0';
                create_directory(filename);
                *last_slash = '/';
            }

            // Write to working directory
            write_file(filename, content, size);
            free(content);
        }
    }

    // Update HEAD
    set_head(target_hash);

    printf("Checked out commit %s\n", target_hash);
}

// Reset command
void reset(const char* commit_hash) {
    // Read commit
    Commit commit;
    if (!read_commit(commit_hash, &commit)) {
